import React, { useState, useEffect } from 'react';
import axios from 'axios';

function RestaurantOrders({ user }) {
  const [orders, setOrders] = useState([]);

  useEffect(() => {
    if (user && user.restaurant_id) {
      fetchOrders();
    }
  }, [user]);

  const fetchOrders = async () => {
    try {
      const response = await axios.get(`http://localhost:5000/orders/restaurant/${user.restaurant_id}`);
      setOrders(response.data.reverse());
    } catch (error) {
      console.error("Error fetching restaurant orders:", error);
    }
  };

  const updateStatus = async (orderId, newStatus) => {
    try {
      await axios.put(`http://localhost:5000/orders/${orderId}/status`, { status: newStatus });
      fetchOrders();
    } catch (error) {
      console.error("Error updating status:", error);
    }
  };

  return (
    <div>
      <h1>INCOMING ORDERS</h1>
      {orders.length === 0 ? (
        <p>NO ORDERS FOR YOUR RESTAURANT YET</p>
      ) : (
        <div className="restaurant-grid">
          {orders.map(order => (
            <div key={order._id} className="order-card" style={{ background: order.status === 'pending' ? '#fff9f0' : 'white' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                <span style={{ fontWeight: 900 }}>ORDER #{order._id.slice(-6)}</span>
                <span className="status-badge" style={{ background: order.status === 'delivered' ? '#e1f5fe' : '#fff3e0' }}>{order.status}</span>
              </div>
              <p style={{ fontSize: '0.9rem', margin: '0.5rem 0' }}>Customer: {order.user_id.name}</p>
              <p style={{ fontSize: '0.8rem', opacity: 0.7 }}>Address: {order.user_id.address}</p>
              <hr />
              <div style={{ margin: '1rem 0' }}>
                {order.items.map((item, idx) => (
                  <div key={idx} style={{ fontSize: '0.9rem' }}>{item.name} x {item.quantity}</div>
                ))}
              </div>
              <div style={{ display: 'flex', gap: '0.5rem', marginTop: '1rem' }}>
                {order.status === 'pending' && (
                  <button className="button" style={{ padding: '0.5rem', fontSize: '0.8rem' }} onClick={() => updateStatus(order._id, 'preparing')}>START PREPARING</button>
                )}
                {order.status === 'preparing' && (
                  <button className="button" style={{ padding: '0.5rem', fontSize: '0.8rem', backgroundColor: '#27ae60' }} onClick={() => updateStatus(order._id, 'delivered')}>MARK AS DELIVERED</button>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default RestaurantOrders;
